import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function CreatePage() {
  const [userLists, setUserLists] = useState([]);
  const [selectedList, setSelectedList] = useState(null);
  const [editMode, setEditMode] = useState(false);
  const [formData, setFormData] = useState({
    listName: '',
    description: '',
    isPublic: false,
    destinationIds: []
  });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const navigate = useNavigate();
  const { isAuthenticated } = useAuth();

  useEffect(() => {
    if (!isAuthenticated) {
      navigate('/login');
      return;
    }
    fetchUserLists();
  }, [isAuthenticated, navigate]);

  const fetchUserLists = async () => {
    try {
      const response = await fetch('http://localhost:3000/api/lists', {
        headers: {
          'x-auth-token': localStorage.getItem('token')
        }
      });
      const data = await response.json();
      setUserLists(data.filter(list => list.userId._id === JSON.parse(atob(localStorage.getItem('token').split('.')[1]))._id));
    } catch (error) {
      setError('Failed to fetch lists');
    }
  };

  const handleListSelect = (list) => {
    setSelectedList(list);
    setFormData({
      listName: list.listName,
      description: list.description || '',
      isPublic: list.isPublic,
      destinationIds: list.destinationIds
    });
    setEditMode(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    try {
      const response = await fetch(`http://localhost:3000/api/lists/${selectedList.listName}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'x-auth-token': localStorage.getItem('token')
        },
        body: JSON.stringify({
          ...formData,
          lastEdited: new Date()
        })
      });

      if (!response.ok) throw new Error('Failed to update list');

      setSuccess('List updated successfully');
      fetchUserLists();
    } catch (error) {
      setError(error.message);
    }
  };

  const handleDelete = async () => {
    if (!window.confirm('Are you sure you want to delete this list?')) return;

    try {
      const response = await fetch(`http://localhost:3000/api/lists/${selectedList.listName}`, {
        method: 'DELETE',
        headers: {
          'x-auth-token': localStorage.getItem('token')
        }
      });

      if (!response.ok) throw new Error('Failed to delete list');

      setSuccess('List deleted successfully');
      setSelectedList(null);
      setEditMode(false);
      fetchUserLists();
    } catch (error) {
      setError(error.message);
    }
  };

  return (
    <div className="isolate bg-white px-6 py-24 sm:py-32 lg:px-8">
      <div className="mx-auto max-w-2xl text-center">
        <h2 className="text-3xl font-bold tracking-tight text-gray-900 sm:text-4xl">
          Manage Your Lists
        </h2>

        {error && <p className="mt-4 text-red-600">{error}</p>}
        {success && <p className="mt-4 text-green-600">{success}</p>}

        <div className="mt-8">
          <h3 className="text-xl font-semibold mb-4">Your Lists</h3>
          <div className="space-y-4">
            {userLists.map(list => (
              <button
                key={list._id}
                onClick={() => handleListSelect(list)}
                className={`w-full p-4 text-left border rounded-lg hover:bg-gray-50 ${
                  selectedList?._id === list._id ? 'border-green-600' : 'border-gray-200'
                }`}
              >
                <h4 className="font-medium">{list.listName}</h4>
                <p className="text-sm text-gray-500">
                  {list.description || 'No description'}
                </p>
                <p className="text-sm text-gray-500">
                  {list.isPublic ? 'Public' : 'Private'} • 
                  {list.destinationIds.length} destinations
                </p>
                {list.lastEdited && (
                  <p className="text-xs text-gray-400">
                    Last edited: {new Date(list.lastEdited).toLocaleDateString()}
                  </p>
                )}
              </button>
            ))}
          </div>
        </div>

        {editMode && selectedList && (
          <form onSubmit={handleSubmit} className="mt-8 space-y-4">
            <div className="text-left">
              <label className="block text-sm font-medium text-gray-700">
                List Name
              </label>
              <input
                type="text"
                value={formData.listName}
                onChange={(e) => setFormData({ ...formData, listName: e.target.value })}
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-green-500 focus:ring-green-500"
                required
              />
            </div>

            <div className="text-left">
              <label className="block text-sm font-medium text-gray-700">
                Description
              </label>
              <textarea
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-green-500 focus:ring-green-500"
                rows={3}
              />
            </div>

            <div className="text-left">
              <label className="flex items-center">
                <input
                  type="checkbox"
                  checked={formData.isPublic}
                  onChange={(e) => setFormData({ ...formData, isPublic: e.target.checked })}
                  className="rounded border-gray-300 text-green-600 focus:ring-green-500"
                />
                <span className="ml-2 text-sm text-gray-700">Make this list public</span>
              </label>
            </div>

            <div className="flex gap-4">
              <button
                type="submit"
                className="flex-1 rounded-md bg-green-600 px-3.5 py-2.5 text-sm font-semibold text-white shadow-sm hover:bg-green-500 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-green-600"
              >
                Save Changes
              </button>
              <button
                type="button"
                onClick={handleDelete}
                className="flex-1 rounded-md bg-red-600 px-3.5 py-2.5 text-sm font-semibold text-white shadow-sm hover:bg-red-500 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-red-600"
              >
                Delete List
              </button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
}
